+    fn next_shell_token_bounds(input: &str, from: usize) -> Option<(usize, usize)> {
+        let bytes = input.as_bytes();
+        let mut idx = from;
+        while idx < bytes.len() && bytes[idx].is_ascii_whitespace() {
+            idx += 1;
+        }
+        if idx >= bytes.len() {
+            return None;
+        }
+
+        let start = idx;
+        let mut in_single = false;
+        let mut in_double = false;
+        while idx < bytes.len() {
+            let byte = bytes[idx];
+            if in_single {
+                if byte == b'\'' {
+                    in_single = false;
+                }
+                idx += 1;
+                continue;
+            }
+            if in_double {
+                if byte == b'\\' && idx + 1 < bytes.len() {
+                    idx += 2;
+                    continue;
+                }
+                if byte == b'"' {
+                    in_double = false;
+                }
+                idx += 1;
+                continue;
+            }
+
+            match byte {
+                b'\'' => {
+                    in_single = true;
+                    idx += 1;
+                }
+                b'"' => {
+                    in_double = true;
+                    idx += 1;
+                }
+                b'\\' if idx + 1 < bytes.len() => {
+                    idx += 2;
+                }
+                _ if byte.is_ascii_whitespace() => break,
+                _ => {
+                    idx += 1;
+                }
+            }
+        }
+
+        Some((start, idx))
